                                                var version=document.getElementById("version-ruangadmin");
                                                version.innerHTML="Version 1.0.1";
                                                function editStatus(attendanceId, currentStatus) {
                                                    Swal.fire({
                                                        title: 'Modifier le statut',
                                                        input: 'select',
                                                        inputOptions: {
                                                            '1': 'Présent ✓',
                                                            '0': 'Absent ✗'
                                                        },
                                                        inputValue: currentStatus.toString(),  // garde la valeur actuelle sélectionnée
                                                        showCancelButton: true,
                                                        confirmButtonColor: '#10b981',         // vert moderne
                                                        cancelButtonColor: '#ef4444',          // rouge
                                                        confirmButtonText: 'Enregistrer',
                                                        cancelButtonText: 'Annuler',
                                                        reverseButtons: true
                                                    }).then((result) => {
                                                        if (result.isConfirmed) {
                                                            const newStatus = result.value;
                                                
                                                            // Si pas de changement → on prévient gentiment
                                                            if (newStatus === currentStatus.toString()) {
                                                                Swal.fire({
                                                                    icon: 'info',
                                                                    title: 'Aucun changement',
                                                                    text: 'Le statut est resté le même.',
                                                                    timer: 1800,
                                                                    showConfirmButton: false
                                                                });
                                                                return;
                                                            }
                                                
                                                            // Envoi de la mise à jour via fetch (plus moderne que XMLHttpRequest)
                                                            fetch('updateAttendance.php', {
                                                                method: 'POST',
                                                                headers: {
                                                                    'Content-Type': 'application/x-www-form-urlencoded',
                                                                },
                                                                body: `Id=${attendanceId}&status=${newStatus}`
                                                            })
                                                            .then(response => response.text())
                                                            .then(data => {
                                                                Swal.fire({
                                                                    icon: data.includes('succès') ? 'success' : 'error',
                                                                    title: data.includes('succès') ? 'Mis à jour !' : 'Erreur',
                                                                    text: data,
                                                                    timer: data.includes('succès') ? 1600 : undefined,
                                                                    showConfirmButton: !data.includes('succès')
                                                                }).then(() => {
                                                                    if (data.includes('succès')) {
                                                                        location.reload();  // recharge la page pour voir le changement
                                                                    }
                                                                });
                                                            })
                                                            .catch(() => {
                                                                Swal.fire({
                                                                    icon: 'error',
                                                                    title: 'Erreur',
                                                                    text: 'Problème de connexion au serveur.'
                                                                });
                                                            });
                                                        }
                                                    });
                                                }